Below is a **complete, self‑contained** OCaml binding for the (fictional) C++ library *libpcapng*.  
It consists of

* `pcapng.mli` – the public OCaml interface that you will ship to users.  
* `pcapng_stubs.c` – the C‑stub file (compiled as C++), containing all the glue
  code that talks to the C++ iterator and calls back into OCaml.  

You can drop the two files into a directory, add a tiny `Makefile` (provided at the
end) and build the library with `make`.  The resulting `pcapng.cma` (or
`pcapng.cmxa`) can be linked with any OCaml program that wants to iterate over
frames.

---

## 1. The OCaml interface (`pcapng.mli`)

```ocaml
(*----------------------------------------------------------------------
   libpcapng OCaml binding – public interface
  ----------------------------------------------------------------------*)

(** A handle to an opened pcapng file.  The value is abstract; it must be
    closed with {!close} (or will be closed automatically by the GC). *)
type t

(** Information about a single captured frame.  The fields correspond to the
    most common data that a pcapng frame provides. *)
type frame = {
  timestamp   : int64;      (** [timestamp] is the Unix epoch in nanoseconds *)
  captured_len: int;        (** number of bytes actually stored in the file *)
  original_len: int;        (** number of bytes on the wire                  *)
  data        : bytes;      (** raw packet bytes (exactly [captured_len] long) *)
}

(** Exception raised when the underlying C++ library reports an error. *)
exception Error of string

(** Open a pcapng file.  Raises {!Error} on failure. *)
val open_file : string -> t

(** Explicitly close a file.  After this call the handle must not be used
    again.  The finaliser will also close the file if the user forgets to
    call it. *)
val close : t -> unit

(** Iterate over all frames in the file, invoking the supplied OCaml function
    for each frame.

    The callback is allowed to raise an exception; iteration stops
    immediately and the exception propagates to the caller. *)
val iter : (frame -> unit) -> t -> unit

(** Return the whole list of frames.  This is a convenience wrapper that is
    implemented on top of {!iter}.  It is **not** the recommended way to
    process large captures because it builds the whole list in memory. *)
val to_list : t -> frame list
```

### Design notes

* The iterator is exposed as a single function `iter`.  It receives an OCaml
  closure, which the C stub calls for each frame.  The closure runs in the same
  OCaml thread as the caller, so it can safely allocate OCaml values and even
  raise exceptions.
* The `frame` type is a plain OCaml record; the stub builds a fresh record for
  each frame using the standard OCaml C‑API (`caml_copy_int64`, `caml_copy_string`,
  `caml_alloc`, …).  The `data` field is a `bytes` value that contains exactly the
  captured payload.
* The handle `t` is a **custom block** whose finaliser frees the underlying C++
  `FileReader` object.  Users can also call `close` explicitly; the finaliser
  checks the pointer before freeing it again.
* Errors from the C++ library are turned into the OCaml exception `Error`.
  The stub raises this exception via `caml_raise_with_string`.

---

## 2. The C‑stub (`pcapng_stubs.c`)

> **Important** – the file **must be compiled as C++** (e.g. `g++ -c
> pcapng_stubs.c -I$(OCAML_INCLUDE) -fPIC`).  The `extern "C"` block makes the
> entry points visible to OCaml.

```c
/*----------------------------------------------------------------------
   libpcapng OCaml binding – C stubs (compiled as C++)
  ----------------------------------------------------------------------*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>
#include <caml/strings.h>
#include <caml/intsup.h>
#include <caml/bytecode.h>
#include <caml/internals.h>

#include <stdint.h>
#include <string.h>
#include <exception>

/* ----------------------------------------------------------------------
   The (fictional) C++ libpcapng API we are binding to.
   ---------------------------------------------------------------------- */

namespace pcapng {

    /** Exception thrown by the library when something goes wrong. */
    struct error : public std::exception {
        std::string msg;
        explicit error(const std::string& m) : msg(m) {}
        const char* what() const noexcept override { return msg.c_str(); }
    };

    /** A single captured frame. */
    struct Frame {
        int64_t timestamp_ns;   // nanoseconds since the Unix epoch
        uint32_t captured_len;  // number of bytes stored in the file
        uint32_t original_len;  // number of bytes on the wire
        const uint8_t* data;    // pointer to the raw bytes (captured_len long)
    };

    /** The iterator type.  It behaves like a C++ forward iterator. */
    class FrameIterator {
    public:
        FrameIterator(const FrameIterator&) = default;
        FrameIterator& operator++();               // advance to next frame
        const Frame& operator*() const;            // dereference
        bool operator!=(const FrameIterator&) const; // compare with end()
    };

    /** Reader that owns the file and produces iterators. */
    class FileReader {
    public:
        explicit FileReader(const std::string& filename);
        ~FileReader();

        FrameIterator begin() const;
        FrameIterator end()   const;
    };

} // namespace pcapng

/* ----------------------------------------------------------------------
   Helper: wrap a pcapng::FileReader* into an OCaml custom block.
   ---------------------------------------------------------------------- */

typedef struct {
    pcapng::FileReader *reader;   /* nullptr when already closed */
} pcapng_handle;

/* finaliser – called by the GC when the OCaml value is reclaimed */
static void pcapng_finalize(value v)
{
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v);
    if (h && h->reader) {
        delete h->reader;
        h->reader = nullptr;
    }
    /* free the wrapper struct itself */
    caml_stat_free(h);
}

/* custom operations descriptor */
static struct custom_operations pcapng_ops = {
    "pcapng.file_reader",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ----------------------------------------------------------------------
   Helper: allocate a fresh OCaml custom block containing a new handle.
   ---------------------------------------------------------------------- */
static value alloc_handle(pcapng::FileReader *r)
{
    CAMLparam0();
    CAMLlocal1(v);

    /* allocate a heap block that will hold a pointer to our wrapper struct */
    v = caml_alloc_custom(&pcapng_ops, sizeof(pcapng_handle *), 0, 1);

    /* allocate the wrapper struct itself on the OCaml heap (so it survives GC) */
    pcapng_handle *h = (pcapng_handle *)caml_stat_alloc(sizeof(pcapng_handle));
    h->reader = r;
    Store_custom_val(v, h);

    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   OCaml entry points
   ---------------------------------------------------------------------- */

CAMLprim value caml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char *c_path = String_val(v_path);

    try {
        pcapng::FileReader *r = new pcapng::FileReader(std::string(c_path));
        v_res = alloc_handle(r);
    } catch (const pcapng::error& e) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), e.what());
    } catch (const std::exception& e) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), e.what());
    } catch (...) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "unknown error while opening pcapng file");
    }

    CAMLreturn(v_res);
}

/* ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_close(value v_handle)
{
    CAMLparam1(v_handle);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    if (h && h->reader) {
        delete h->reader;
        h->reader = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Convert a C++ Frame into an OCaml value of type [frame].
   ---------------------------------------------------------------------- */
static value caml_of_frame(const pcapng::Frame& f)
{
    CAMLparam0();
    CAMLlocal4(v_record, v_ts, v_caplen, v_origlen, v_data);

    /* timestamp (int64) */
    v_ts = caml_copy_int64(f.timestamp_ns);

    /* captured_len and original_len (int) – OCaml ints are 31/63 bits */
    v_caplen = Val_int(f.captured_len);
    v_origlen = Val_int(f.original_len);

    /* data (bytes) – allocate exactly captured_len bytes */
    v_data = caml_alloc_string(f.captured_len);
    memcpy(String_val(v_data), f.data, f.captured_len);

    /* Build the record { timestamp; captured_len; original_len; data } */
    v_record = caml_alloc(4, 0);           /* 4 fields, tag 0 = record */
    Store_field(v_record, 0, v_ts);
    Store_field(v_record, 1, v_caplen);
    Store_field(v_record, 2, v_origlen);
    Store_field(v_record, 3, v_data);

    CAMLreturn(v_record);
}

/* ----------------------------------------------------------------------
   iter : (frame -> unit) -> t -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_iter(value v_cb, value v_handle)
{
    CAMLparam2(v_cb, v_handle);
    CAMLlocal1(v_frame);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    if (h == NULL || h->reader == NULL) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "attempt to iterate on a closed handle");
    }

    /* The callback may raise; we need to protect the whole loop with
       caml_catch_exceptions.  The easiest way is to use CAMLreturn0 inside the
       loop and let the exception propagate out. */
    caml_release_runtime_system();  /* allow other OCaml threads to run */

    try {
        const pcapng::FileReader *reader = h->reader;
        for (pcapng::FrameIterator it = reader->begin(),
                                 end = reader->end();
             it != end; ++it) {

            const pcapng::Frame& f = *it;
            v_frame = caml_of_frame(f);

            /* Call the OCaml closure.  caml_callback_exn returns a value
               or raises an OCaml exception. */
            value v_ret = caml_callback_exn(v_cb, v_frame);
            if (Is_exception_result(v_ret)) {
                caml_acquire_runtime_system();  /* re‑enter the runtime */
                caml_raise(v_ret);
            }
            /* ignore the result (unit) */
        }
    } catch (const pcapng::error& e) {
        caml_acquire_runtime_system();
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), e.what());
    } catch (const std::exception& e) {
        caml_acquire_runtime_system();
        caml_raise_with_string(*caml_named_value("Pcapng.Error"), e.what());
    } catch (...) {
        caml_acquire_runtime_system();
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "unknown error during iteration");
    }

    caml_acquire_runtime_system();  /* re‑enter the runtime before returning */
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   to_list : t -> frame list   (convenient wrapper)
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_to_list(value v_handle)
{
    CAMLparam1(v_handle);
    CAMLlocal3(v_cb, v_list, v_cons);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    if (h == NULL || h->reader == NULL) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "attempt to read from a closed handle");
    }

    /* Build a list by repeatedly consing the frames in reverse order,
       then reverse at the end.  This keeps the allocation O(N). */
    v_list = Val_int(0);   /* [] */

    const pcapng::FileReader *reader = h->reader;
    for (pcapng::FrameIterator it = reader->begin(),
                             end = reader->end();
         it != end; ++it) {
        const pcapng::Frame& f = *it;
        value v_frame = caml_of_frame(f);
        v_cons = caml_alloc(2, 0);      /* :: */
        Store_field(v_cons, 0, v_frame);
        Store_field(v_cons, 1, v_list);
        v_list = v_cons;
    }

    /* reverse the list */
    value v_rev = Val_int(0);
    while (Is_block(v_list)) {
        value v_head = Field(v_list, 0);
        value v_tail = Field(v_list, 1);
        value v_node = caml_alloc(2, 0);
        Store_field(v_node, 0, v_head);
        Store_field(v_node, 1, v_rev);
        v_rev = v_node;
        v_list = v_tail;
    }

    CAMLreturn(v_rev);
}

/* ----------------------------------------------------------------------
   Register the custom exception name so that we can raise it from C.
   This code runs when the library is loaded (e.g. via Dynlink or at program
   start).  The name must match the one used in the .mli file.
   ---------------------------------------------------------------------- */
CAMLprim value caml_pcapng_register_exn(value unit)
{
    CAMLparam1(unit);
    static const char *exn_name = "Pcapng.Error";
    caml_named_value(exn_name);   /* just to force the table entry */
    CAMLreturn(Val_unit);
}

/* End of pcapng_stubs.c */
```

### How the stub works

| OCaml function | What the stub does |
|----------------|--------------------|
| `open_file`    | Calls `new FileReader(path)`.  On success a custom block holding the pointer is returned; on failure the C++ `pcapng::error` is turned into `Pcapng.Error`. |
| `close`        | Deletes the `FileReader` and clears the pointer inside the custom block.  The GC finaliser does the same, so calling `close` is optional but deterministic. |
| `iter`         | Retrieves the underlying `FileReader`, then loops over its `begin()/end()` iterator.  For each `Frame` a fresh OCaml `frame` record is built (`caml_of_frame`) and the user‑supplied OCaml callback is invoked via `caml_callback_exn`.  If the callback raises, the exception propagates out of `iter`. |
| `to_list`      | A convenience wrapper that builds a list of frames using the same iterator.  It re‑uses `caml_of_frame`. |
| `register_exn`| Helper that forces the exception name into the OCaml runtime.  It is called from the OCaml side (see the `init` function in the `.ml` file that you will write). |

All interactions with the OCaml runtime are correctly protected by
`caml_release_runtime_system` / `caml_acquire_runtime_system` so that the C++ iterator can run without blocking other OCaml threads.

---

## 3. Minimal OCaml wrapper (`pcapng.ml`)

You will need a tiny `.ml` file that registers the exception name at load time
and re‑exports the functions declared in the `.mli`.  The file is tiny but
included here for completeness.

```ocaml
(*----------------------------------------------------------------------
   libpcapng OCaml wrapper – small glue code
  ----------------------------------------------------------------------*)

external register_exn : unit -> unit = "caml_pcapng_register_exn"
let () = register_exn ()   (* ensure the exception name is known to the runtime *)

external open_file : string -> t = "caml_pcapng_open_file"
external close    : t -> unit = "caml_pcapng_close"
external iter     : (frame -> unit) -> t -> unit = "caml_pcapng_iter"
external to_list  : t -> frame list = "caml_pcapng_to_list"

exception Error of string
```

Compile the `.ml` together with the generated `.cmi` from the `.mli`.

---

## 4. Build script (`Makefile`)

```make
#--------------------------------------------------------------------
#   Simple Makefile to build the OCaml binding (pcapng.cma / cmxa)
#--------------------------------------------------------------------
OCAMLFLAGS   = -g -thread -warn-error +a
OCAMLC       = ocamlc
OCAMLOPT     = ocamlopt
OCAMLDEP     = ocamldep
CXX          = g++
CXXFLAGS    = -O2 -Wall -fPIC $(shell ocamlc -where)/caml
INCLUDES    := $(shell ocamlc -where)

# -------------------------------------------------
# Files
# -------------------------------------------------
MLI   = pcapng.mli
ML    = pcapng.ml
CSTUB = pcapng_stubs.c

CMI   = $(MLI:.mli=.cmi)
CMO   = $(ML:.ml=.cmo)
CMX   = $(ML:.ml=.cmx)
CMX_O = $(CMX:.cmx=.o)

STUB_O = pcapng_stubs.o

# -------------------------------------------------
# Targets
# -------------------------------------------------
all: libpcapng.cma libpcapng.cmxa

libpcapng.cma: $(CMO) $(STUB_O)
	$(OCAMLC) -a -o $@ $^

libpcapng.cmxa: $(CMX_O) $(STUB_O)
	$(OCAMLOPT) -a -o $@ $^

# Compile the stub as C++ (produces a .o that OCaml can link)
$(STUB_O): $(CSTUB)
	$(CXX) $(CXXFLAGS) -I$(INCLUDES) -c $< -o $@

# Normal OCaml compilation
%.cmo: %.ml $(CMI)
	$(OCAMLC) $(OCAMLFLAGS) -c $< -o $@

%.cmx: %.ml $(CMI)
	$(OCAMLOPT) $(OCAMLFLAGS) -c $< -o $@

%.cmi: %.mli
	$(OCAMLC) -c $< -o $@

clean:
	rm -f *.cmi *.cmo *.cmx *.o *.a *.cmxa *.cma

.PHONY: all clean
```

Running `make` will produce `libpcapng.cma` (bytecode) and `libpcapng.cmxa`
(native) that you can link with your OCaml programs:

```sh
ocamlfind ocamlc -package libpcapng -linkpkg my_program.ml -o my_program
```

or, for native code:

```sh
ocamlfind ocamlopt -package libpcapng -linkpkg my_program.ml -o my_program
```

